var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`귀하의 종신계약 권유에 대한 답을 산출하는 중.`,JPN:`終身契約勧誘への回答を算出中。`,ENG:`Looking for an appropriate answer to your lifetime contract offer...`,TWN:`對於您「終身契約」的提議，正在計算答案……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`본 기체는 사장님의 의사를 적극적으로 존중합니다.`,JPN:`本機は社長の意思を積極的に尊重します。`,ENG:`I highly respect your opinions.`,TWN:`本機將積極尊重老闆的意志。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_UI_RECRUITMNET_HELICOPTER_LOOP`},{id:`L13_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`죄송합니다. 논리회로에 부하가 걸리면 가끔 이렇게 프로펠러가 오작동을 일으키곤 합니다.`,JPN:`申し訳ありません。論理回路に負荷がかかると、時々こうしてプロペラが誤作動を起こすことがあります。`,ENG:`My apologies. My propeller tends to malfunction when my logic circuit is overloaded.`,TWN:`非常抱歉。要是邏輯回路出現負荷，螺旋槳有時會出現這種故障。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`......걱정 마십시오. 위협이 아닙니다.`,JPN:`……ご安心ください。威嚇ではありません。`,ENG:`Please rest assured that I'm not trying to threaten you.`,TWN:`……請不用擔心。這不是威脅。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`BUZZARD_SL_NULL_NULL`,text:{KOREA:`제가 유기체였다면, 이것은 행복하다는 표현에 가깝습니다.`,JPN:`有機体の動きで例えるなら、これは幸福な状態の表現に近いでしょう。`,ENG:`If I was an organism, this would have been an expression of happiness.`,TWN:`如果我是生物的話，這種反應就是「幸福」的表現。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BUZZARD_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};